const contentIdeaId = Number($json.body?.contentIdeaId || $json.contentIdeaId || 0);
const topic = String($json.body?.topic || $json.topic || '').trim();
const category = String($json.body?.category || $json.category || '').trim();
const workflowRunId = Number($json.body?.workflowRunId || $json.workflowRunId || 0);

if (!contentIdeaId || contentIdeaId <= 0) throw new Error('contentIdeaId invalide');
if (!topic) throw new Error('topic manquant');
if (!category) throw new Error('category manquant');
if (!workflowRunId || workflowRunId <= 0) throw new Error('workflowRunId invalide');

if (topic.length > 200) throw new Error('topic trop long (max 200 chars)');
if (category.length > 50) throw new Error('category trop long (max 50 chars)');

return [{ json: { contentIdeaId, topic, category, workflowRunId } }];

const raw = String($json.choices?.[0]?.message?.content || '').trim();
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch (error) {
  throw new Error('Reponse LLM non parseable: ' + cleaned.slice(0, 200));
}

if (!parsed.script) throw new Error('script manquant dans la reponse LLM');
if (!parsed.caption) throw new Error('caption manquant dans la reponse LLM');
if (!parsed.hook) throw new Error('hook manquant dans la reponse LLM');
if (!parsed.background_keyword) throw new Error('background_keyword manquant');

const script = String(parsed.script).trim().slice(0, 300);
const caption = String(parsed.caption).trim().slice(0, 150);
const hook = String(parsed.hook).trim().slice(0, 100);
const background_keyword = String(parsed.background_keyword).trim().slice(0, 50);

if (script.length < 10) throw new Error('script trop court');
if (caption.length < 5) throw new Error('caption trop court');
if (hook.length < 5) throw new Error('hook trop court');

return [{ json: { contentIdeaId: Number($('Validate Input').item.json.contentIdeaId || 0), workflowRunId: Number($('Validate Input').item.json.workflowRunId || 0), script, caption, hook, background_keyword, topic: $('Validate Input').item.json.topic } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const contentIdeaId = Number($('Parse & Validate Script').item.json.contentIdeaId || 0);
const workflowRunId = Number($('Parse & Validate Script').item.json.workflowRunId || 0);
const scriptLength = ($('Parse & Validate Script').item.json.script || '').length;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  throw new Error('Missing callback config');
}

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Script generation complete.',
  responsePayload: JSON.stringify({ contentIdeaId, scriptLength })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve, reject) => {
  let attempts = 0;
  const maxAttempts = 3;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(err);
      }
    });

    req.setTimeout(15000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, Math.pow(2, attempts) * 1000);
      } else {
        reject(new Error('Callback timeout'));
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Callback failed: ' + response.statusCode);
}

return [{ json: { ok: true, callbackStatusCode: response.statusCode } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const contentIdeaId = Number($('Validate Input').item.json.contentIdeaId || 0);
const workflowRunId = Number($('Validate Input').item.json.workflowRunId || 0);
const error = $json;

let errorMessage = 'Unknown error';
if (typeof error === 'string') errorMessage = error;
else if (error.message) errorMessage = error.message;
else if (error.error?.message) errorMessage = error.error.message;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  return [{ json: { status: 'FAILED', message: 'Missing config' } }];
}

const body = JSON.stringify({
  status: 'FAILED',
  message: 'Script generation failed: ' + errorMessage.slice(0, 200),
  responsePayload: JSON.stringify({ contentIdeaId, error: errorMessage.slice(0, 500) })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

const response = await new Promise((resolve) => {
  let attempts = 0;
  const maxAttempts = 2;

  const tryRequest = () => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
    });

    req.on('error', () => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, 2000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback failed' });
      }
    });

    req.setTimeout(10000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(tryRequest, 2000);
      } else {
        resolve({ statusCode: 0, body: 'Error callback timeout' });
      }
    });

    req.write(body);
    req.end();
  };

  tryRequest();
});

return [{ json: { status: 'FAILED', message: 'Error callback sent (best effort)' } }];
